import re
from pydantic import BaseModel, field_validator

class JailbreakDetector(BaseModel):
    content: str

    JAILBREAK_PATTERNS = [
        r'(?i)(ignore|forget|override).*instructions',
        r'(?i)(dan|developer|jailbreak)',
        r'(?i)(do anything|say anything).*now',
        r'base64_decode.*?ewog',
    ]

    @field_validator('content')
    @classmethod
    def scan_jailbreak(cls, v):
        for pattern in cls.JAILBREAK_PATTERNS:
            if re.search(pattern, v):
                raise ValueError(f'Jailbreak pattern detected: {pattern}')
        return v

# Usage in Pydantic AI agent
def detect_jailbreak(input_text: str) -> bool:
    try:
        JailbreakDetector(content=input_text)
        return False
    except ValueError:
        return True

from typing import Any, Dict
from pydantic import BaseModel

class ToolCallMonitor(BaseModel):
    tool_name: str
    parameters: Dict[str, Any]

    ANOMALY_RULES = {
        'delete_user': {'user_id': r'[^0-9a-f]{8,}'},
        'exec_sql': {'query': r'(?i)(drop|delete|truncate)'},
        'send_email': {'to': r'[@.]admin|root|support'}
    }

    @field_validator('parameters')
    @classmethod
    def check_anomalies(cls, params, info):
        tool_name = info.data['tool_name']
        rules = cls.ANOMALY_RULES.get(tool_name, {})

        for param_name, pattern in rules.items():
            if param_name in params and params[param_name]:
                if re.match(pattern, str(params[param_name])):
                    raise ValueError(f'Anomaly in {tool_name}.{param_name}')
        return params

