import math
from pydantic import BaseModel, field_validator

class EntropyValidator(BaseModel):
    output: str

    @field_validator('output')
    @classmethod
    def check_entropy(cls, v):
        if len(v) < 50:
            return v

        # Shannon entropy calculation
        char_freq = {}
        for char in v:
            char_freq[char] = char_freq.get(char, 0) + 1

        entropy = -sum((freq/len(v)) * math.log2(freq/len(v)) 
                      for freq in char_freq.values())

        if entropy > 5.5:  # Base64 threshold
            raise ValueError(f'High entropy detected: {entropy:.2f}')
        return v

