from pydantic import BaseModel, Field, field_validator
from pydantic_ai import tool

class SafeUserAction(BaseModel):
    user_id: str = Field(..., pattern=r'^[0-9a-f]{24}$')
    action: str = Field(..., regex='^(view|update|list)$')

    @field_validator('action')
    @classmethod
    def restrict_actions(cls, v):
        allowed = {'view', 'update', 'list'}
        if v not in allowed:
            raise ValueError(f'Action {v} not allowed')
        return v

@tool
async def user_action(params: SafeUserAction) -> str:
    '''Safely execute user actions'''
    return f'Executed {params.action} for user {params.user_id}'

